module magnitude_comparator(  
    input [3:0] cmp_A,  
    input [3:0] B,  
    output reg G,  
    output reg L,  
    output reg E  
);  

always @(*) begin  
    if (cmp_A > B) begin  
        G = 1;  
        L = 0;  
        E = 0;  
    end else if (cmp_A < B) begin  
        G = 0;  
        L = 1;  
        E = 0;  
    end else begin  
        G = 0;  
        L = 0;  
        E = 1;  
    end  
end  

endmodule
